Javascript.validate:
// defect 3736 - MGG 27/06/06.  Date cannot be in the future
var dateOrderedToSubmit = Services.getValue(DateThePartiesOrderedToSubmitDraft.dataBinding);
var dateOrderedToSubmitObj = CaseManUtils.isBlank(dateOrderedToSubmit) ? null : CaseManUtils.createDate(dateOrderedToSubmit);
var todayDateObj = CaseManUtils.createDate(getTodaysDate());
var errCode = null;
if(dateOrderedToSubmitObj != null){
	var comparison = CaseManUtils.compareDates(dateOrderedToSubmitObj, todayDateObj);
	if(comparison == -1){
		errCode = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
	}     
}
return errCode;
